import React, { useMemo } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";
import { useTranslation } from "../i18n";

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";
const BG = "#F5F5F5";
const WHITE = "#FFFFFF";

function SectionCard({
  tone = "blue", // blue | teal | amber | navy
  title,
  subtitle,
  iconLeft = "🚕",
  children,
  rightPillText,
  rightPillTone = "green", // green | gray
  bottomProgress = false,
}) {
  const toneStyle = toneStyles[tone] || toneStyles.blue;

  return (
    <View style={[S.card, toneStyle.card]}>
      {/* Header */}
      <View style={[S.cardHeader, toneStyle.header]}>
        <View style={S.headerLeft}>
          <Text style={S.headerIcon}>{iconLeft}</Text>
          <Text style={S.headerTitle}>
            {title} {subtitle ? <Text style={S.headerSub}>({subtitle})</Text> : null}
          </Text>
        </View>

        {rightPillText ? (
          <View
            style={[
              S.pill,
              rightPillTone === "green" ? S.pillGreen : S.pillGray,
            ]}
          >
            <Text style={S.pillText}>{rightPillText}</Text>
          </View>
        ) : null}
      </View>

      {/* Body */}
      <View style={S.cardBody}>{children}</View>

      {/* Bottom progress (like the example “active bar”) */}
      {bottomProgress ? (
        <View style={S.progressWrap}>
          <View style={S.progressTrack}>
            <View style={S.progressFill} />
          </View>
        </View>
      ) : null}
    </View>
  );
}

function InfoRow({ icon = "•", label, value, valueBold = true }) {
  return (
    <View style={S.row}>
      <Text style={S.rowIcon}>{icon}</Text>
      <Text style={S.rowLabel}>{label}</Text>
      <Text style={[S.rowValue, valueBold && S.rowValueBold]} numberOfLines={2}>
        {value}
      </Text>
    </View>
  );
}

/** ✅ No real picture: we use an avatar circle with an icon or initials */
function DriverHeader({ name }) {
  const initials = (name || "")
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((s) => s[0]?.toUpperCase())
    .join("");

  return (
    <View style={S.driverTop}>
      <View style={S.avatar}>
        {/* Either initials or an icon */}
        <Text style={S.avatarText}>{initials || "👤"}</Text>
      </View>

      <View style={{ flex: 1 }}>
        <Text style={S.driverName}>{name}</Text>
      </View>
    </View>
  );
}

